import{_ as l,c as e,o as t,ag as o}from"./chunks/framework.ELrfyV9R.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-15-space.md","filePath":"ai/2026-03/2026-03-15-space.md","lastUpdated":1774394626000}'),r={name:"ai/2026-03/2026-03-15-space.md"};function i(p,a,h,s,d,n){return t(),e("div",null,a[0]||(a[0]=[o('<p>昨晚前端哥社群组织了一场160分钟的直播，主题就是：创业那些事。参与人员众多：有连续创业者，也有985双一流硕士、海外留学生，还有电商大佬、万粉大V，更有失业者和一批焦虑的程序员等等讨论空前激烈，全程我旁听在做，思虑万分，有太多的话想问，却又不知如何开口。</p><p>对于一个从来没有创业的人来说，这些难能宝贵的经验，就如同一把打开现实世界的钥匙，能让我更快的从空想走向真正的行动。</p><p>在此我特地整理了20条我个人觉得直播中比较核心的内容，重点不分先后，因为每个人的视角不一样。</p><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2><ol><li>抛弃程序员思维，坚持需求和市场先行</li></ol><p>我本身也是个程序员，程序员或者技术人员常犯的错误就是先闭门造车打磨产品，等到做的自己认为完美了，再去寻找用户，但是这时候市场可能已经被占领了。</p><p>正确的做法可能：如果有了初步的想法，先确定一下市场需求和目标用户，再去做相应的产品。做出的东西哪怕极其粗糙（“一坨屎”），也要先想办法尝试卖出去，有了真实成交才有底气继续迭代。</p><h2 id="-1" tabindex="-1"><a class="header-anchor" href="#-1" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="2"><li>拥抱不确定性是创业与打工的核心区别</li></ol><p>对于眼下跟我一样，还在打工的大部分人来说，本质上是在做一份已经被定义好的工作：岗位是什么、工资多少、该做什么，公司基本都替你规划好了，你只需要把事情完成。</p><p>创业的话可能就不一样了，创业没有标准答案。你要一边摸索市场到底需要什么，一边根据赚钱压力和团队情况不断调整方向，本质上是在不确定中边做边找方向。</p><h2 id="-2" tabindex="-1"><a class="header-anchor" href="#-2" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="3"><li>找准商业对标，坚持产品的标准化</li></ol><p>普通人创业，很难完全从0到1 打造一个全新项目，因此寻找市场上已经出现增长苗头的真实需求（对标）是重中之重。</p><p>同时，创业项目必须具备标准化的能力，纯定制化的项目难以形成规模化，而且成本极高，只适合作为高客单价的阶梯产品，不适合用来打通核心市场。</p><h2 id="-3" tabindex="-1"><a class="header-anchor" href="#-3" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="4"><li>拒绝完美主义与精神内耗，快速行动优于一切</li></ol><p>完美主义往往是由于自卑或畏难心理产生的逃避借口，会导致行动迟缓并错失市场先机。</p><p>不要为了追求产品的极致而迟迟不肯发布，粗糙的开始肯定是比毫无进展要好的多。要在发布后，坚持每天复盘或得到真实的反馈中去解决问题。</p><h2 id="-4" tabindex="-1"><a class="header-anchor" href="#-4" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="5"><li>赚钱的本质在于利用信息差与打破圈子壁垒</li></ol><p>很多人因为使用了最新的AI大模型快速开发出应用而觉得自身很强，其实不是你厉害，是平台厉害，这本质上是利用了信息差。</p><p>商业社会中信息差永远存在，创业者必须多走出去社交、交流，打破固有的圈子，才能捕捉到真正的红利和搞钱的机会。</p><h2 id="-5" tabindex="-1"><a class="header-anchor" href="#-5" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="6"><li>培养商业共情能力，借助自媒体放大技术价值</li></ol><p>技术人员极具潜力，但往往只跟同行交流，缺乏商业共情能力。</p><p>如果能将高深的技术降维，做成平易近人的保姆级实操教程（明确告诉小白点哪个按钮、能实现什么商业价值），在短视频平台上分发，极易获得庞大的流量，从而接触到海量的真实市场需求。</p><h2 id="-6" tabindex="-1"><a class="header-anchor" href="#-6" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="7"><li>放弃长远的技术规划，专注当下的快速变现</li></ol><p>因为AI和机器人的发展日新月异，任何一门手艺或技术都有可能在几年后被迅速替代，因此做五年、十年的长期技术规划意义已经不大。当下最理智的做法是利用手头的AI工具和信息差，尽力追求业务落地和快速变现，把钱装进自己口袋里才是最实际的。</p><h2 id="-7" tabindex="-1"><a class="header-anchor" href="#-7" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="8"><li>闭门造车是死路，必须在真实的碰撞中获取市场反馈</li></ol><p>就像去华尔街找实习，不能只靠在家里苦读金融圣经一样，做项目也不能只在家里敲代码。</p><p>必须主动的走出去，通过大量的面试或将产品推向市场挨骂、碰壁后得到比较有效的真实反馈，来不断反思并调整自己的方向，否则脱离了市场自己什么都不知道。</p><h2 id="-8" tabindex="-1"><a class="header-anchor" href="#-8" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="9"><li>AI时代个人的想法与敏锐度比纯底层技术更重要</li></ol><p>随着AI编程能力的飞速提升，纯写代码的技术门槛正在大幅降低。</p><p>现在只要有好的商业想法，能够戳中市场的细分痛点（如解决给女朋友拍照需求的简单应用），结合AI工具就能快速落地并创造巨大的收入。一款产品能在市场上存活，往往是因为市场做的好，而不一定是因为底层代码写得最牛。</p><h2 id="-9" tabindex="-1"><a class="header-anchor" href="#-9" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="10"><li>传统行业与B端的AI私有化部署存在独特的壁垒与机会</li></ol><p>与C端用户直接调用国外大模型不同，欧洲的传统行业（如银行、保险、政企等）以及国内的特种行业，极度重视数据隐私和安全，要求私有化部署和严格的人工审核。这些自带专业门槛的行业虽然AI推进节奏较慢，但竞争相对较小，为有行业背景的AI创业者提供了高成功率的独特商业机会。</p><h2 id="-10" tabindex="-1"><a class="header-anchor" href="#-10" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="11"><li>圈层决定信息差，需主动花钱或花精力破圈</li></ol><p>创业者不能总是待在家里或固有的圈子里闭门造车，不同的圈层（如南方与北方的搞钱路子）存在巨大的信息差。</p><p>主动去结交不同行业的人，甚至花几千块钱去采访卖面条或做披萨的老板，能迅速获取一整套真实的商业逻辑和网感。</p><h2 id="-11" tabindex="-1"><a class="header-anchor" href="#-11" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="12"><li>做个人IP切忌盲目追求泛流量，真实记录最重要</li></ol><p>如果在社交平台上做个人IP，不要为了流量去发与自己定位无关的娱乐八卦内容。</p><p>应该全方位展现真实的自我，哪怕你是小白，每天真实记录并分享自己“学了1+1=2”的过程，也比发不相关的泛流量内容更有长期商业价值。</p><h2 id="-12" tabindex="-1"><a class="header-anchor" href="#-12" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="13"><li>“先赚到第一笔钱”是产品跑通与建立信心的核心</li></ol><p>不要总是期待将产品打磨到极致再推向市场，哪怕做出来的东西极其粗糙（像“一坨屎”），也必须想尽办法先卖出去。只有产生真实的商业成单，才能带来继续优化产品的资金和信心，否则就会陷入自我感动的闭门造车中。</p><h2 id="-13" tabindex="-1"><a class="header-anchor" href="#-13" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="14"><li>身体健康是保持高强度执行力的基础</li></ol><p>创业如同打仗，而身体的器官（如肝脏）就是打仗的将军。很多创业者缺乏执行力或脾气大，本质上就是因为熬夜等不良习惯导致身体机能下降。</p><p>先自我审视，管理好身体健康和作息，才有可能在创业的持久战中脱颖而出。</p><h2 id="-14" tabindex="-1"><a class="header-anchor" href="#-14" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="15"><li>AI不仅是工具，更在重塑职场结构与公司考核指标</li></ol><p>随着AI编程能力（如Cursor、Claude Code Codex）的进化，公司内部正在发生结构性变化，如强制要求后端或前端转型为全栈并接管更多业务线。</p><p>AI大幅提高了单人的产出效率，这不仅会导致公司将AI熟练度列入核心考核，甚至会加速传统岗位的裁员潮。</p><h2 id="-15" tabindex="-1"><a class="header-anchor" href="#-15" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="16"><li>市场占有率远比底层代码的优雅和纯粹性更重要</li></ol><p>用户并不关心底层代码写得有多好，他们只在乎UI界面和实际体验。</p><p>很多技术极客做出的优秀产品死于没有声量，而一些代码结构粗糙（如“屎山代码”）的项目只要抢占了市场先机并被用户习惯，就能获得巨大的成功和变现空间。</p><h2 id="-16" tabindex="-1"><a class="header-anchor" href="#-16" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="17"><li>AI的智力呈现“锯齿状”，需精准匹配合适的应用场景</li></ol><p>AI在不同领域的表现并非均衡发展，而是呈现出锯齿状的特点。在规则明确、易于验证的领域（如编程、数学竞赛），AI的进步速度极快，甚至能碾压人类。</p><p>但在缺乏明确标准、主观性强的领域（如文学创作），AI的表现依然相对较弱。</p><h2 id="-17" tabindex="-1"><a class="header-anchor" href="#-17" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="18"><li>团队的财富分配机制直接决定了整体战斗力与心流</li></ol><p>创业团队的成功离不开合理的财富分配，好的团队分配机制（例如裁掉一半人，但把原本的工资分配给剩下的一半人）能极大激发员工的潜能。</p><p>当分配到位时，团队成员会进入到毫无怨言的心流工作状态，将多人的力量凝聚成一个拳头。将会极大的发挥团队的战斗力。</p><h2 id="-18" tabindex="-1"><a class="header-anchor" href="#-18" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="19"><li>错过风口是人生常态，无需因错失机会而过度内耗</li></ol><p>无论是早期的比特币、房地产暴涨，还是如今的AI浪潮，绝大多数人在风口刚刚出现时往往是看不清、不相信甚至不参与的。</p><p>这也就说明错过风口是所有人的常态，认清这一点可以避免陷入无意义的焦虑和遗憾中，只需把握当下的机会即可。</p><h2 id="-19" tabindex="-1"><a class="header-anchor" href="#-19" aria-label="Permalink to &quot;&quot;">​</a></h2><ol start="20"><li>多复盘，多复盘，多复盘</li></ol><p>无论你有没有时间，有时间的可以每天对自己、对工作、对AI各个角度进行复盘，时间少的也可以进行每周的复盘。要不然又是浑浑噩噩的一天、一周、一月、一年.....抬头看看2026年已经过去多少天了。</p><h2 id="-20" tabindex="-1"><a class="header-anchor" href="#-20" aria-label="Permalink to &quot;&quot;">​</a></h2><p>最后</p><p>我再从程序员视角强调一下我的想法。当前如果你还在开发的岗位上，我建议你首要目标是快马加鞭的将AI与你的工作进行深度捆绑，尽量用最好的AI，选最好的工具，如果还不舍得花点小钱，还没有醒悟的决心，那么这一轮的淘汰赛必然会轮到你的头上，只是早晚的问题。公司业绩各个方面可能好一些，那么给你的周期可能就稍微长一点。</p><p>如果你是纯前端也不要过于担心，从我公司的情况看，我觉得后端更危险。 同样，如果你是后端，也不要沾沾自喜。只会CRUD的业务仔其实比前端还容易被淘汰。 对于前端转全栈的伙伴们，有时间一定要手动去搭建一套相对完整的后端微服务体系(甚至单体API)都可以的。深入去了解数据库设计、后端权限与安全、整体后端框架搭建、接口并发处理、缓存与消息队列等等。相信我在AI的助力下，后端也不难的。</p><p>最后的最后，我加入前端哥社群本想着只为了搞流量，没想到这里不光光有流量，还能学习到社群中优秀成员的宝贵创业经验，学习如何运营自己，让自己及早的从迷茫的过去，找到前行的方向。</p><p>一个人办不成的事，社群中一群人可以帮你。</p><p>做自媒体搞个人IP要厚脸皮，甚至不要脸。</p><p>我一直记得前端哥讲过：做自媒体就是要自信高调。</p>',87)]))}const b=l(r,[["render",i]]);export{u as __pageData,b as default};
